'use strict';

const fs = require('fs');
const path = require('path');

function fsrs(pathExtension) {
  const pathDir = path.join(process.cwd(), pathExtension);
  const filenames = fs.readdirSync(pathDir);

  const pagePaths = filenames.map(filename => filename.split('.')[0]);

  return pagePaths;
}

exports = module.exports = fsrs;